package echo

import (
	"net/http"
	"testing"

	"github.com/stretchr/testify/assert"
)

// Test for the trailing slash regression issue
func TestTrailingSlashWildcard(t *testing.T) {
	e := New()
	r := e.router

	// Routes
	r.Add(http.MethodGet, "/articles", func(Context) error {
		return nil
	})
	r.Add(http.MethodGet, "/articles/*", func(Context) error {
		return nil
	})

	c := e.NewContext(nil, nil).(*context)

	// This should match /articles/* and return empty wildcard parameter
	r.Find(http.MethodGet, "/articles/", c)
	if c.handler == nil {
		t.Error("Expected to find handler for /articles/, but got 404")
	} else {
		assert.Equal(t, "", c.Param("*"))
	}

	// This should also match /articles/*
	r.Find(http.MethodGet, "/articles/whatever", c)
	if c.handler == nil {
		t.Error("Expected to find handler for /articles/whatever, but got 404")
	} else {
		assert.Equal(t, "whatever", c.Param("*"))
	}
}
EOF
